    val recipes: List<Recipe> = listOf(
        Recipe(1, "Snert (Dutch Erwtensoep)", "Classic Dutch split pea soup with smoked sausage and pork belly.", "Winter", listOf("500g split peas", "1 smoked sausage (rookworst)", "200g pork belly", "2 onions, chopped", "2 leeks, sliced", "1 celeriac, diced", "2 liters water", "Salt and pepper"), listOf("Rinse split peas and boil in water with pork belly for 1.5 hours.", "Add chopped vegetables (onions, leeks, celeriac) and simmer for another 30 minutes.", "Remove pork belly, chop into small pieces, and return to soup.", "Slice smoked sausage and add to the soup, simmering for 10 minutes.", "Season with salt, pepper, and fresh celery leaves before serving with rye bread.")),
        Recipe(2, "Vermicelli Soup", "A comforting, clear vegetable soup with fine vermicelli noodles.", "Winter", listOf("100g vermicelli noodles", "1.5 liters vegetable broth", "150g mixed soup vegetables (carrots, leeks, celery)", "100g chicken breast, shredded", "Parsley, finely chopped", "Salt and pepper"), listOf("Bring vegetable broth to a boil in a large pot.", "Add shredded chicken breast and soup vegetables.", "Simmer on low heat for 15 minutes until vegetables are tender.", "Stir in vermicelli noodles and cook for 5 minutes.", "Season with salt and pepper, garnish with chopped parsley, and serve hot.")),
        Recipe(3, "Boerenkool Stamppot", "Traditional Dutch mashed potatoes and curly kale with a rich gravy.", "Winter", listOf("1kg potatoes, peeled", "500g curly kale, chopped", "1 smoked sausage", "50g butter", "100ml warm milk", "1 tbsp vinegar", "Salt, pepper, and nutmeg"), listOf("Boil potatoes and kale together in a large pot with water for 25 minutes.", "Place the smoked sausage on top of the kale to heat through during the last 15 minutes.", "Remove the sausage and drain the potato-kale mixture.", "Mash thoroughly with butter, milk, vinegar, salt, pepper, and nutmeg.", "Serve hot with sliced sausage and a pool of rich meat gravy.")),
        Recipe(4, "Hutspot", "Dutch comfort food made of mashed potatoes, carrots, and onions.", "Winter", listOf("1kg potatoes, peeled", "600g carrots, chopped", "400g onions, chopped", "150g bacon lardons", "50g butter", "50ml milk", "Salt and white pepper"), listOf("Boil potatoes, carrots, and onions in salted water for 25 minutes until tender.", "Meanwhile, fry the bacon lardons in a pan until crispy.", "Drain the vegetables, reserving a little cooking liquid.", "Mash the vegetables with butter, milk, salt, and white pepper.", "Stir in the crispy bacon and serve hot.")),
        Recipe(5, "Hachee", "A traditional Dutch beef and onion stew cooked slow to melt-in-the-mouth perfection.", "Winter", listOf("500g beef chuck, cubed", "500g onions, sliced", "2 bay leaves", "3 cloves", "1 tbsp vinegar", "1 slice of gingerbread", "50g butter", "500ml beef broth"), listOf("Melt butter in a heavy pot and sear the beef cubes until browned.", "Add the sliced onions and cook until translucent.", "Pour in beef broth and vinegar, and add bay leaves and cloves.", "Lid the pot and simmer on very low heat for 2.5 to 3 hours.", "Stir in crumbled gingerbread to thicken the stew and simmer for another 15 minutes.")),
        Recipe(6, "Zuurkool Stamppot", "Savory mashed potatoes and sauerkraut, often sweetened with pineapple or raisins.", "Winter", listOf("1kg potatoes, peeled", "500g sauerkraut, drained", "150g bacon lardons", "100g pineapple tidbits", "50g butter", "100ml milk", "Salt and pepper"), listOf("Boil potatoes in salted water for 20 minutes.", "In a separate pot, simmer sauerkraut with a splash of water for 15 minutes.", "Fry bacon lardons until crispy in a frying pan.", "Drain potatoes and mash with butter, milk, salt, and pepper.", "Mix in the drained sauerkraut, crispy bacon, and pineapple tidbits before serving.")),
        Recipe(7, "Hungarian Goulash", "Rich, hearty beef stew flavored with sweet Hungarian paprika.", "Winter", listOf("600g beef stew meat, cubed", "3 onions, chopped", "2 bell peppers, chopped", "2 cloves garlic, minced", "2 tbsp paprika powder", "1 can chopped tomatoes", "400ml beef stock", "Bay leaf"), listOf("Sauté onions and garlic in a large pot with oil until soft.", "Add beef cubes and brown on all sides.", "Stir in paprika powder, then immediately add chopped tomatoes, bell peppers, stock, and bay leaf.", "Cover and simmer gently for 2 hours until beef is extremely tender.", "Season with salt, black pepper, and serve with potatoes or noodles.")),
        Recipe(8, "French Onion Soup", "Classic Parisian soup with caramelized onions and a cheesy baguette crouton.", "Winter", listOf("1kg yellow onions, thinly sliced", "50g butter", "1 liter beef broth", "100ml dry white wine", "1 baguette", "150g Gruyere cheese, grated", "Thyme and bay leaf"), listOf("Melt butter in a deep pot and cook onions on low heat for 45 minutes, stirring occasionally, until deeply caramelized.", "Deglaze the pot with white wine, scraping up the browned bits.", "Add beef broth, thyme, and bay leaf, then simmer for 25 minutes.", "Slice baguette, toast, and top with grated Gruyere.", "Ladle soup into oven-safe bowls, place bread on top, and broil until cheese is bubbly and brown.")),
        Recipe(9, "Split Pea Stew", "Thick, nourishing winter stew loaded with peas, root vegetables, and pork shank.", "Winter", listOf("500g green split peas", "1 pork shank", "2 carrots, diced", "1 turnip, diced", "1 leek, sliced", "1.5 liters vegetable stock", "Salt, pepper, and fresh thyme"), listOf("In a large pot, combine split peas, pork shank, and vegetable stock. Bring to a boil.", "Reduce heat and simmer for 1 hour, skimming any foam from the surface.", "Add carrots, turnip, and leek, then continue simmering for 45 minutes.", "Remove pork shank, shred the meat, discard bones, and return meat to the pot.", "Season with salt, pepper, and thyme before serving.")),
