        Recipe(251, "White Asparagus Flemish Style", "Traditional Belgian/Dutch spring delicacy with boiled egg and butter sauce.", "Spring", listOf("1kg white asparagus, peeled", "4 eggs, hard-boiled", "150g butter, melted", "100g cooked ham, finely chopped", "Parsley, chopped", "Nutmeg, salt, and pepper"), listOf("Boil the peeled asparagus in salted water with a pinch of sugar for 12 to 15 minutes until tender.", "Finely chop or mash the hard-boiled eggs.", "Arrange hot asparagus on a serving plate.", "Drape with chopped ham, chopped eggs, and fresh parsley.", "Pour warm melted butter over the top and season with nutmeg, salt, and pepper.")),
        Recipe(252, "Spring Rolls with Fresh Herbs", "Crisp, light Vietnamese-style spring rolls packed with vibrant spring herbs.", "Spring", listOf("12 rice paper wrappers", "150g cooked shrimp or tofu, sliced", "100g rice vermicelli noodles", "1 cup fresh mint leaves", "1 cup cilantro", "1 cucumber, julienned", "Peanut dipping sauce"), listOf("Cook vermicelli noodles according to package instructions, then drain and cool.", "Dip a rice paper wrapper in warm water for 5 seconds to soften.", "Lay flat and place shrimp/tofu, noodles, cucumber, mint, and cilantro in the lower third.", "Fold in the sides and roll up tightly.", "Serve immediately with peanut dipping sauce.")),
        Recipe(253, "Spring Herb Risotto", "Creamy Italian arborio rice infused with fresh wild garlic and spring greens.", "Spring", listOf("300g Arborio rice", "1 liter warm vegetable broth", "1 onion, finely diced", "150g asparagus tips", "100g peas", "50g wild garlic or ramps, chopped", "50g Parmesan, grated", "50g butter"), listOf("Sauté onions in butter until soft. Add Arborio rice and toast for 2 minutes.", "Add vegetable broth one ladle at a time, stirring constantly until absorbed.", "Halfway through (about 10 mins), stir in asparagus tips and peas.", "When rice is tender but al dente, stir in wild garlic, remaining butter, and Parmesan.", "Remove from heat, cover for 2 minutes, and serve immediately.")),
        Recipe(254, "Spring Lentil Soup", "A light, zesty green lentil soup with fresh lemon and spinach.", "Spring", listOf("250g green lentils", "1 onion, diced", "2 carrots, sliced", "1 liter vegetable stock", "100g baby spinach", "Juice of 1 lemon", "2 tbsp olive oil", "Salt and cumin"), listOf("Heat olive oil in a pot and sauté onion and carrots for 5 minutes.", "Add green lentils, cumin, and vegetable stock. Bring to a boil.", "Reduce heat, cover, and simmer for 30 minutes until lentils are soft.", "Stir in baby spinach until wilted.", "Finish with fresh lemon juice and salt to taste.")),
        Recipe(255, "Asparagus & Goat Cheese Quiche", "Savory tart loaded with green asparagus spears and creamy goat cheese.", "Spring", listOf("1 pre-made pie crust", "200g green asparagus, trimmed", "150g soft goat cheese", "4 eggs", "200ml heavy cream", "Salt, pepper, and fresh thyme"), listOf("Preheat oven to 190°C (375°F) and blind-bake the pie crust for 10 minutes.", "Blanch green asparagus in boiling water for 3 minutes, then shock in ice water.", "Whisk eggs, heavy cream, salt, pepper, and thyme together in a bowl.", "Arrange asparagus and crumbled goat cheese in the pre-baked crust.", "Pour egg mixture over them and bake for 35 minutes until golden and set.")),
        Recipe(256, "Radish & Cucumber Spring Salad", "Crisp, refreshing salad dressed with a tangy dill yogurt dressing.", "Spring", listOf("1 bunch radishes, thinly sliced", "1 English cucumber, sliced", "150g Greek yogurt", "1 tbsp lemon juice", "2 tbsp fresh dill, chopped", "1 tbsp olive oil", "Salt and pepper"), listOf("In a large bowl, whisk together Greek yogurt, lemon juice, olive oil, chopped dill, salt, and pepper.", "Add the sliced radishes and cucumber slices.", "Toss gently until everything is evenly coated.", "Chill in the refrigerator for 15 minutes before serving.", "Garnish with extra dill.")),
