        Recipe(501, "Glazed BBQ Ribs", "Tender, smoky pork ribs brushed with a sweet and sticky barbecue sauce.", "Summer", listOf("2 racks pork baby back ribs", "1 cup BBQ sauce", "2 tbsp brown sugar", "1 tbsp paprika", "1 tsp garlic powder", "Salt and black pepper"), listOf("Preheat oven or smoker to 135°C (275°F).", "Rub ribs with brown sugar, paprika, garlic powder, salt, and pepper.", "Wrap tightly in foil and bake/smoke for 3 hours until tender.", "Remove from foil, brush generously with BBQ sauce.", "Grill or broil for 5-10 minutes per side until glaze is caramelized and bubbling.")),
        Recipe(502, "Summer Gourmet Skewers", "A colorful medley of marinated beef, chicken, and fresh summer vegetables.", "Summer", listOf("300g beef sirloin, cubed", "300g chicken breast, cubed", "1 red bell pepper, chunked", "1 yellow bell pepper, chunked", "1 red onion, chunked", "Olive oil, garlic, rosemary"), listOf("Mix olive oil, minced garlic, chopped rosemary, salt, and pepper in a bowl to make a marinade.", "Marinate beef and chicken cubes for at least 1 hour.", "Thread meat alternating with bell peppers and onions onto skewers.", "Grill over medium-high heat for 10-12 minutes, turning occasionally.", "Serve hot with garlic herb butter.")),
        Recipe(503, "Andalucian Gazpacho", "Chilled Spanish tomato and vegetable soup, perfect for hot summer days.", "Summer", listOf("1kg ripe tomatoes", "1 cucumber, peeled", "1 green bell pepper", "1 clove garlic", "2 tbsp sherry vinegar", "100ml extra virgin olive oil", "Salt and cold water"), listOf("Roughly chop tomatoes, cucumber, bell pepper, and garlic.", "Place chopped vegetables in a blender and puree until completely smooth.", "With the motor running, slowly drizzle in olive oil and sherry vinegar.", "Season with salt. Add a splash of cold water if too thick.", "Strain through a sieve (optional), chill in the fridge for at least 2 hours, and serve cold.")),
        Recipe(504, "Mediterranean Pasta Salad", "Cold pasta tossed with cherry tomatoes, kalamata olives, feta, and vinaigrette.", "Summer", listOf("300g fusilli or penne pasta", "200g cherry tomatoes, halved", "100g feta cheese, crumbled", "100g Kalamata olives, pitted", "1 cucumber, diced", "Italian vinaigrette dressing"), listOf("Cook pasta in salted boiling water until al dente, drain, and rinse with cold water.", "In a large bowl, combine cooled pasta, cherry tomatoes, cucumber, olives, and feta.", "Pour Italian vinaigrette over the salad and toss well.", "Cover and chill in the refrigerator for 1 hour to let flavors blend.", "Garnish with fresh basil leaves before serving.")),
        Recipe(505, "Caprese Salad with Pesto", "Classic Italian summer salad showcasing ripe tomatoes, mozzarella, and basil.", "Summer", listOf("4 large ripe tomatoes, sliced", "250g fresh buffalo mozzarella, sliced", "1 bunch fresh basil leaves", "3 tbsp extra virgin olive oil", "2 tbsp balsamic glaze", "Salt and pepper"), listOf("On a large serving platter, alternate slices of tomato and mozzarella.", "Tuck fresh basil leaves between the tomato and mozzarella slices.", "Drizzle extra virgin olive oil and balsamic glaze over the entire platter.", "Season with flaky sea salt and freshly cracked black pepper.", "Serve immediately at room temperature.")),
        Recipe(506, "Grilled Sea Bass", "Light, flaky whole sea bass grilled with lemon, garlic, and fresh herbs.", "Summer", listOf("1 whole sea bass, scaled and gutted", "1 lemon, sliced", "3 cloves garlic, crushed", "Fresh parsley and dill", "2 tbsp olive oil", "Salt and pepper"), listOf("Score the skin of the fish on both sides with a sharp knife.", "Rub the entire fish, inside and out, with olive oil, salt, and pepper.", "Stuff the cavity with lemon slices, garlic, parsley, and dill.", "Grill over medium heat for 7-8 minutes per side until skin is crispy and flesh is flaky.", "Squeeze fresh lemon juice over the fish and serve with grilled vegetables.")),
