        Recipe(751, "Roasted Pumpkin Soup", "Silky, warming soup made with roasted butternut pumpkin and autumn spices.", "Autumn", listOf("1kg pumpkin (Hokkaido or butternut), cubed", "1 onion, chopped", "2 cloves garlic", "500ml vegetable broth", "100ml cooking cream", "Nutmeg, salt, and pepper", "Pumpkin seeds for garnish"), listOf("Preheat oven to 200°C (400°F). Toss pumpkin cubes, onion, and garlic with oil and roast for 25 minutes.", "Transfer roasted vegetables to a soup pot.", "Add vegetable broth and bring to a simmer.", "Puree with an immersion blender until completely smooth.", "Stir in cooking cream, season with nutmeg, salt, and pepper, and garnish with roasted pumpkin seeds.")),
        Recipe(752, "Wild Mushroom Risotto", "Rich, earthy Arborio rice cooked with a variety of wild autumn mushrooms.", "Autumn", listOf("300g Arborio rice", "300g mixed wild mushrooms (chanterelles, porcini, cremini)", "1 liter hot mushroom broth", "1 shallot, finely diced", "100ml dry white wine", "50g butter", "50g Parmesan, grated"), listOf("Sauté wild mushrooms in a pan with butter until browned; set aside.", "In a separate pot, cook shallot in butter, then add rice and toast for 2 minutes.", "Pour in white wine and stir until fully evaporated.", "Gradually add hot mushroom broth, stirring constantly.", "Stir in cooked mushrooms, remaining butter, and Parmesan when rice is tender. Let rest for 2 minutes before serving.")),
        Recipe(753, "Dutch Appeltaart", "Traditional deep-dish apple pie with a spiced cinnamon raisin filling and lattice crust.", "Autumn", listOf("300g flour", "200g butter, cold and cubed", "150g sugar", "1 egg", "1kg apples (Elstar or Jonagold), peeled and sliced", "2 tsp cinnamon", "50g raisins", "50g breadcrumbs"), listOf("Mix flour, butter, sugar, and half of the beaten egg to form a dough; chill for 30 minutes.", "Toss sliced apples with cinnamon, raisins, and a little sugar.", "Grease a springform pan and line it with 3/4 of the dough.", "Sprinkle breadcrumbs on the bottom, then pack tightly with the apple filling.", "Create a lattice top with remaining dough, brush with remaining egg, and bake at 180°C for 60 minutes.")),
        Recipe(754, "Wild Boar Stew", "Slow-cooked game stew infused with red wine, juniper berries, and root vegetables.", "Autumn", listOf("800g wild boar meat, cubed", "2 onions, chopped", "2 carrots, sliced", "300ml bold red wine", "300ml beef stock", "5 juniper berries, crushed", "2 bay leaves", "2 tbsp flour", "50g butter"), listOf("Coat wild boar cubes in flour, salt, and pepper.", "Melt butter in a Dutch oven and sear the meat until deeply browned.", "Add onions, carrots, crushed juniper berries, and bay leaves.", "Pour in red wine and beef stock, bringing it to a simmer.", "Cover and cook on low heat for 3 hours until meat is incredibly tender; adjust seasoning before serving.")),
        Recipe(755, "Autumn Pear & Pecan Salad", "Fresh salad with sweet pears, toasted pecans, and blue cheese dressing.", "Autumn", listOf("2 ripe pears, cored and sliced", "100g mixed baby greens", "75g pecans, toasted", "75g crumbled blue cheese", "3 tbsp olive oil", "1 tbsp apple cider vinegar", "1 tsp honey"), listOf("In a small bowl, whisk olive oil, apple cider vinegar, honey, salt, and pepper to make the vinaigrette.", "Arrange baby greens on a platter.", "Top with sliced pears, toasted pecans, and crumbled blue cheese.", "Drizzle vinaigrette over the salad just before serving.", "Toss gently and serve immediately.")),
        Recipe(756, "Hearty Potato Leek Soup", "Thick and comforting soup perfect for chilly autumn evenings.", "Autumn", listOf("3 large leeks, white and light green parts sliced", "500g potatoes, peeled and diced", "3 cloves garlic, minced", "1 liter vegetable stock", "100ml heavy cream", "2 tbsp olive oil", "Salt and white pepper"), listOf("Heat olive oil in a pot and sauté leeks and garlic until soft (approx. 8 minutes).", "Add diced potatoes and vegetable stock; bring to a boil.", "Reduce heat and simmer for 20 minutes until potatoes are very tender.", "Puree the soup with an immersion blender until smooth.", "Stir in heavy cream, season with salt and white pepper, and serve hot.")),
        Recipe(757, "Slow Braised Wild Boar with Thyme & Rosemary", "A delicious seasonal autumn dish featuring tender wild boar prepared slow braised and perfectly finished with thyme & rosemary.", "Autumn", listOf("500g Wild Boar", "2 tbsp Olive oil or butter", "1 Onion, finely chopped", "2 cloves Garlic, minced", "1 cup seasonal autumn vegetables", "Salt and fresh black pepper to taste", "500ml vegetable or meat stock", "1 Bay leaf and fresh herbs"), listOf("Prepare and portion the wild boar and vegetables accordingly.", "Heat olive oil or butter in a suitable pan or pot.", "Sauté the chopped onion and minced garlic until aromatic and translucent.", "Add the wild boar and cook until nicely browned or fully integrated.", "Stir in the seasonal vegetables and herbs, adjusting seasoning with salt and pepper.", "Cook according to the slow braised method (simmering or roasting as needed) until hot and fully cooked.", "Garnish beautifully and serve hot as a classic autumn meal.")),
